fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    const MAX_VAL: usize = 10000;
    let k = k as usize;
    let m = grid.len();
    let n = grid[0].len();
    if m == 0 || n == 0 {
        return 0;
    }
    let mut dp = vec![vec![vec![i64::MAX; n]; m]; k+1];
    dp[0][0][0] = 0;

    for t in 0..=k {
        let mut heap = BinaryHeap::new();
        for i in 0..m {
            for j in 0..n {
                if dp[t][i][j] != i64::MAX {
                    heap.push((-dp[t][i][j], i, j));
                }
            }
        }

        while let Some((neg_cost, i, j)) = heap.pop() {
            let cost = -neg_cost;
            if cost != dp[t][i][j] {
                continue;
            }
            if i + 1 < m {
                let ni = i + 1;
                let nj = j;
                let next_cost = cost + grid[ni][nj];
                if next_cost < dp[t][ni][nj] {
                    dp[t][ni][nj] = next_cost;
                    heap.push((-next_cost, ni, nj));
                }
            }
            if j + 1 < n {
                let ni = i;
                let nj = j + 1;
                let next_cost = cost + grid[ni][nj];
                if next_cost < dp[t][ni][nj] {
                    dp[t][ni][nj] = next_cost;
                    heap.push((-next_cost, ni, nj));
                }
            }
        }

        if t < k {
            let mut suf = vec![i64::MAX; MAX_VAL+1];
            for i in 0..m {
                for j in 0..n {
                    if dp[t][i][j] == i64::MAX {
                        continue;
                    }
                    let v = grid[i][j] as usize;
                    if dp[t][i][j] < suf[v] {
                        suf[v] = dp[t][i][j];
                    }
                }
            }
            for v in (0..MAX_VAL).rev() {
                if suf[v+1] < suf[v] {
                    suf[v] = suf[v+1];
                }
            }
            for i in 0..m {
                for j in 0..n {
                    let v = grid[i][j] as usize;
                    if suf[v] < dp[t+1][i][j] {
                        dp[t+1][i][j] = suf[v];
                    }
                }
            }
        }
    }

    (0..=k).filter_map(|t| {
        if dp[t][m-1][n-1] == i64::MAX {
            None
        } else {
            Some(dp[t][m-1][n-1])
        }
    }).min().unwrap_or(i64::MAX)
}
